/**
 * segment_stubs.c - Stub definitions for N64 ROM segment symbols
 * and boot.c assembly functions.
 *
 * On N64, these are generated by the linker script. On PC we provide
 * the actual ROM offset values extracted from the N64 ELF so that
 * game code can read data from the loaded ROM image.
 *
 * IMPORTANT: These symbols are declared as `extern u32 *name` in bondgame.h.
 * On N64, they're linker symbols where &name == the ROM offset.
 * On PC, they're variables where the VALUE contains the ROM offset.
 * The PC romCopy (in ramrom.c) handles this difference.
 */
#include <ultra64.h>

/* --- ROM/RAM segment boundary symbols --- */
