/* --- boot.c assembly function stubs --- */
/* boot.c is pure MIPS asm; we stub its exported functions here. */

u32 get_csegmentSegmentStart(void)  { return 0x80020d90; }
u32 get_cdataSegmentRomStart(void)  { return 0x00021990; }
u32 get_cdataSegmentRomEnd(void)    { return 0x00033590; }
u32 get_inflateSegmentRomStart(void){ return 0x00033590; }
u32 get_inflateSegmentRomEnd(void)  { return 0x00034b30; }

u32 jump_decompressfile(u32 source, u32 target, u32 buffer) {
    (void)source; (void)target; (void)buffer;
    return 0;
}

/* From tlb_hardwire.s */
void initTLBPrepareContext(void) {}

